# Supernova / Explosion Effect
# ─────────────────────────────────────────────
class Supernova:
    def __init__(self, x, y):
        self.x = x
        self.y = y
        self.t = 0.0
        self.duration = 2.2
        self.alive = True
        self.rings = [
            {'color': (255, 255, 255), 'speed': 180, 'width': 4},
            {'color': (180, 60, 220),  'speed': 140, 'width': 3},
            {'color': (180, 20, 60),   'speed': 100, 'width': 3},
            {'color': (0, 220, 200),   'speed': 70,  'width': 2},
        ]
        # Debris particles
        self.particles = []
        for _ in range(80):
            angle = random.uniform(0, 2 * math.pi)
            speed = random.uniform(30, 220)
            self.particles.append({
                'x': x, 'y': y,
                'vx': math.cos(angle) * speed,
                'vy': math.sin(angle) * speed,
                'life': random.uniform(0.6, 2.0),
                'age': 0.0,
                'size': random.randint(1, 3),
                'color': random.choice([
                    (255, 200, 100), (255, 100, 180),
                    (100, 255, 200), (200, 150, 255)
                ])
            })

    def update(self, dt):
        self.t += dt
        for p in self.particles:
            p['age'] += dt
            p['vx'] *= 0.97
            p['vy'] *= 0.97
            p['x'] += p['vx'] * dt
            p['y'] += p['vy'] * dt
        if self.t >= self.duration:
            self.alive = False

    def draw(self, surface):
        progress = self.t / self.duration

        # Flash at center
        if self.t < 0.15:
            flash_alpha = int(255 * (1 - self.t / 0.15))
            flash_r = min(int(self.t / 0.15 * 300), 80)
            flash_surf = pygame.Surface((flash_r * 2 + 2, flash_r * 2 + 2), pygame.SRCALPHA)
            pygame.draw.circle(flash_surf, (255, 255, 255, flash_alpha),
                               (flash_r + 1, flash_r + 1), flash_r)
            surface.blit(flash_surf, (int(self.x) - flash_r - 1, int(self.y) - flash_r - 1))

        # Expanding rings
        for ring in self.rings:
            radius = int(ring['speed'] * self.t)
            alpha = max(0, int(255 * (1 - progress) * 0.8))
            if radius > 0 and alpha > 5:
                ring_surf = pygame.Surface((radius * 2 + 10, radius * 2 + 10), pygame.SRCALPHA)
                c = ring['color'] + (alpha,)
                pygame.draw.circle(ring_surf, c,
                                   (radius + 5, radius + 5), radius, ring['width'])
                surface.blit(ring_surf, (int(self.x) - radius - 5, int(self.y) - radius - 5))

        # Debris particles
        for p in self.particles:
            if p['age'] < p['life']:
                fade = 1.0 - p['age'] / p['life']
                alpha = int(255 * fade)
                c = p['color'] + (alpha,)
                ps = pygame.Surface((p['size'] * 2 + 2, p['size'] * 2 + 2), pygame.SRCALPHA)
                pygame.draw.circle(ps, c, (p['size'] + 1, p['size'] + 1), p['size'])
                surface.blit(ps, (int(p['x']) - p['size'] - 1, int(p['y']) - p['size'] - 1))


# ─────────────────────────────────────────────
# Main
# ─────────────────────────────────────────────
def main():
    audio = AudioEngine()
    stars = [Star() for _ in range(NUM_STARS)]
    supernovas = []

    # Background surface (static starfield layer)
    bg = pygame.Surface((WIDTH, HEIGHT))
    bg.fill((0, 0, 0))

    # Nebula background (subtle gradient blobs)
    nebula = pygame.Surface((WIDTH, HEIGHT), pygame.SRCALPHA)
    for _ in range(6):
        nx = random.randint(0, WIDTH)
        ny = random.randint(0, HEIGHT)
        nr = random.randint(120, 300)
        nc = random.choice([
            (20, 0, 40, 18), (0, 10, 40, 15), (30, 10, 0, 12)
        ])
        pygame.draw.circle(nebula, nc, (nx, ny), nr)

    running = True
    prev_time = time.time()

    print("Stellar Drift running. Move mouse to attract stars. Click for supernova. Close window to exit.")

    while running:
        now = time.time()
        dt = min(now - prev_time, 0.05)
        prev_time = now

        mx, my = pygame.mouse.get_pos()

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_ESCAPE:
                    running = False
            elif event.type == pygame.MOUSEBUTTONDOWN:
                if event.button == 1:
                    sx, sy = event.pos
                    supernovas.append(Supernova(sx, sy))
                    audio.trigger_explosion(sx)

                    # Affect nearby stars
                    explosion_radius = 200
                    for star in stars:
                        dx = star.x - sx
                        dy = star.y - sy
                        dist = math.sqrt(dx * dx + dy * dy)
                        if dist < explosion_radius:
                            # Blast outward
                            if dist > 1:
                                force = (explosion_radius - dist) / explosion_radius * 8.0
                                star.vx += (dx / dist) * force
                                star.vy += (dy / dist) * force
                            # Rebirth
                            star.reborn = True
                            star.has_trail = True
                            star.trail.clear()
                            if random.random() < 0.5:
                                star.color_base = (255, 80, 160)
                            else:
                                star.color_base = (80, 255, 120)

        # Update stars
        attracted_count = 0
        for star in stars:
            star.update(mx, my, dt)
            if star.attracted:
                attracted_count += 1

        audio.set_star_count(attracted_count)

        # Update supernovas
        for sn in supernovas:
            sn.update(dt)
        supernovas = [sn for sn in supernovas if sn.alive]

        # ── Draw ──
        screen.fill((0, 0, 2))
        screen.blit(nebula, (0, 0))

        # Draw stars
        for star in stars:
            star.draw(screen)

        # Draw supernovas
        for sn in supernovas:
            sn.draw(screen)

        # Subtle vignette
        vignette = pygame.Surface((WIDTH, HEIGHT), pygame.SRCALPHA)
        for r_step in range(5):
            radius = WIDTH // 2 + r_step * 40
            alpha = 8
            pygame.draw.circle(vignette, (0, 0, 0, alpha),
                               (WIDTH // 2, HEIGHT // 2), radius,
                               40 + r_step * 10)
        screen.blit(vignette, (0, 0))

        pygame.display.flip()
        clock.tick(60)

    audio.stop()
    pygame.quit()
    print("Stellar Drift closed.")


if __name__ == "__main__":
    main()